/// Grace period before an `Earliest` resolve is allowed to spawn an empty payload fallback.
///
/// Duration is specified in seconds or in milliseconds if the value ends with `ms`.
#[arg(long = "builder.empty-payload-grace", value_parser = parse_duration_from_secs_or_ms, default_value = "200ms", value_name = "DURATION")]
pub empty_payload_grace: Duration,

